∀ {P : Core.Problem} {S : CT4.Spec P} {capability : CT4.Capability S} {input : CT4.Input P}
  (self : CT4.AssignmentState S capability input) (demand : S.Demand),
  self.assigned demand = none → CT4.MissingAt S input demand

∀ {P : Core.Problem} {S : CT4.Spec P} {capability : CT4.Capability S} {input : CT4.Input P}
  (self : CT4.AssignmentState S capability input) (demand : S.Demand) (payer : S.Payer),
  self.assigned demand = some payer → S.Eligible input demand payer
